'use client'

import { useState, useEffect } from 'react'

export default function NicknameModal({ isOpen, onClose, onSubmit, onReset, initialNickname, targetName }) {
  const [nickname, setNickname] = useState(initialNickname || '')

  useEffect(() => {
    if (isOpen) {
      setNickname(initialNickname || '')
    }
  }, [isOpen, initialNickname])

  if (!isOpen) return null

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-content liquid-glass" onClick={(e) => e.stopPropagation()}>
        <div className="modal-header">
          <h3 className="modal-title">เปลี่ยนชื่อเล่นสำหรับ {targetName}</h3>
          <button className="modal-close" onClick={onClose}>
            <i className="bi bi-x-lg"></i>
          </button>
        </div>
        <div className="modal-body">
          <div className="input-group">
            <label className="modal-label">ชื่อเล่นใหม่</label>
            <input
              type="text"
              className="modal-input"
              value={nickname}
              onChange={(e) => setNickname(e.target.value)}
              placeholder="ป้อนชื่อเล่นที่ต้องการ..."
              autoFocus
              onKeyDown={(e) => {
                if (e.key === 'Enter') onSubmit(nickname)
                if (e.key === 'Escape') onClose()
              }}
            />
          </div>
        </div>
        <div className="modal-footer">
          <div className="footer-left">
            <button className="btn-reset" onClick={() => onReset()}>
              <i className="bi bi-arrow-counterclockwise"></i> คืนค่าชื่อเดิม
            </button>
          </div>
          <div className="footer-right">
            <button className="btn-cancel" onClick={onClose}>ยกเลิก</button>
            <button className="btn-submit" onClick={() => onSubmit(nickname)}>บันทึก</button>
          </div>
        </div>

        <style jsx>{`
          .modal-overlay {
            position: fixed;
            top: 0;
            left: 0;
            right: 0;
            bottom: 0;
            background: rgba(0, 0, 0, 0.7);
            backdrop-filter: blur(4px);
            display: flex;
            align-items: center;
            justify-content: center;
            z-index: 9999;
            animation: fadeIn 0.2s ease-out;
          }
          .modal-content {
            width: 90%;
            max-width: 480px;
            min-width: 320px;
            padding: 30px;
            background: rgba(22, 27, 34, 0.98);
            border: 1px solid rgba(255, 255, 255, 0.15);
            border-radius: 28px;
            box-shadow: 0 25px 50px rgba(0, 0, 0, 0.5);
            animation: slideUp 0.3s cubic-bezier(0.34, 1.56, 0.64, 1);
          }
          .modal-header {
            display: flex;
            justify-content: space-between;
            align-items: center;
            margin-bottom: 24px;
            gap: 16px;
          }
          .modal-title {
            font-size: 1.35rem;
            font-weight: 800;
            margin: 0;
            color: #fff;
            line-height: 1.3;
          }
          .modal-close {
            background: rgba(255, 255, 255, 0.05);
            border: 1px solid rgba(255, 255, 255, 0.1);
            color: #8b949e;
            cursor: pointer;
            width: 36px;
            height: 36px;
            border-radius: 12px;
            display: flex;
            align-items: center;
            justify-content: center;
            font-size: 1rem;
            transition: all 0.2s;
            flex-shrink: 0;
          }
          .modal-close:hover {
            background: rgba(255, 255, 255, 0.1);
            color: #fff;
            transform: rotate(90deg);
          }
          .modal-body {
            margin-bottom: 30px;
          }
          .input-group {
            display: flex;
            flex-direction: column;
            gap: 10px;
          }
          .modal-label {
            display: block;
            font-size: 0.95rem;
            color: #8b949e;
            font-weight: 600;
            margin-left: 4px;
          }
          .modal-input {
            width: 100%;
            background: rgba(0, 0, 0, 0.3);
            border: 1px solid rgba(255, 255, 255, 0.1);
            border-radius: 14px;
            padding: 14px 18px;
            color: #fff;
            font-size: 1.05rem;
            outline: none;
            transition: all 0.2s;
          }
          .modal-input:focus {
            border-color: #58a6ff;
            background: rgba(0, 0, 0, 0.4);
            box-shadow: 0 0 0 4px rgba(88, 166, 255, 0.15);
          }
          .modal-footer {
            display: flex;
            justify-content: space-between;
            align-items: center;
            gap: 16px;
            flex-wrap: wrap;
          }
          .footer-right {
            display: flex;
            gap: 12px;
            flex: 1;
            justify-content: flex-end;
          }
          .btn-submit {
            background: #238636;
            color: white;
            border: none;
            padding: 12px 24px;
            border-radius: 14px;
            font-weight: 700;
            font-size: 1rem;
            cursor: pointer;
            transition: all 0.2s;
            white-space: nowrap;
          }
          .btn-submit:hover {
            background: #2ea043;
            transform: translateY(-2px);
            box-shadow: 0 8px 20px rgba(35, 134, 54, 0.3);
          }
          .btn-cancel {
            background: rgba(255, 255, 255, 0.05);
            color: #fff;
            border: 1px solid rgba(255, 255, 255, 0.1);
            padding: 12px 24px;
            border-radius: 14px;
            font-weight: 700;
            font-size: 1rem;
            cursor: pointer;
            transition: all 0.2s;
            white-space: nowrap;
          }
          .btn-cancel:hover {
            background: rgba(255, 255, 255, 0.1);
            transform: translateY(-2px);
          }
          .btn-reset {
            background: transparent;
            color: #f85149;
            border: 1px solid rgba(248, 81, 73, 0.2);
            padding: 10px 16px;
            border-radius: 12px;
            font-weight: 700;
            font-size: 0.9rem;
            cursor: pointer;
            transition: all 0.2s;
            display: flex;
            align-items: center;
            gap: 8px;
            white-space: nowrap;
          }
          .btn-reset:hover {
            background: rgba(248, 81, 73, 0.1);
            border-color: #f85149;
            transform: translateY(-2px);
          }
          @keyframes fadeIn {
            from { opacity: 0; }
            to { opacity: 1; }
          }
          @keyframes slideUp {
            from { transform: translateY(20px); opacity: 0; }
            to { transform: translateY(0); opacity: 1; }
          }
        `}</style>
      </div>
    </div>
  )
}
